3	type Step = { op: string; items: { type: string }[] };
4	
5	type Scenario = {
6	  customer: { yearsWithMHPCO: number };
7	  steps: Step[];
8	};
9	
10	type StepResult = { premium: number };
11	
12	type ScenarioResult = {
13	  results: StepResult[];
14	};
15	
16	const BASE_PREMIUMS: Record<string, number> = {
17	  sword: 100,
18	  amulet: 60,
19	  staff: 80,
20	  potion: 40,
21	  rune: 25,
22	};
23	
24	const FIRST_INSURANCE_SURCHARGE_RATE = 0.1;
25	const PROCESSING_FEE = 5;
26	
27	const RUNE_BLOCK_SIZE = 3;
28	const RUNE_BLOCK_BASE_PREMIUM = 60;
29	
30	const quoteStep = (step: Step): StepResult => {
31	  const totalBasePremium =
32	    step.items.length === RUNE_BLOCK_SIZE
33	      ? RUNE_BLOCK_BASE_PREMIUM
34	      : step.items.reduce((total, item) => total + BASE_PREMIUMS[item.type], 0);
35	  const firstInsuranceSurcharge =
36	    totalBasePremium * FIRST_INSURANCE_SURCHARGE_RATE;
37	  return {
38	    premium: Math.ceil(
39	      totalBasePremium + firstInsuranceSurcharge + PROCESSING_FEE,
40	    ),
41	  };
42	};
43	
44	export const processScenario = (scenario: Scenario): ScenarioResult => ({
45	  results: scenario.steps.map(quoteStep),
46	});
